import React from 'react'
import { Dashboardmenu } from './components/Dashboardmenu'
import { DashboardContent } from './components/DashboardContent'

export const Dashboard = () => {
  return (
    <div className='dashboard'>
      <div>
        {Dashboardmenu}
      </div>
      <div>
        {DashboardContent}
      </div>
    </div>
  )
}
